class FilterHandler{constructor(){this._filters=[]}get filters(){return this._filters}set filters(t){this._filters=t}hasFilter(e){return null==e?0<this.filters.length:this.filters.some(t=>e<=t&&t<=e)}applyFilters(){}notifyListeners(t){}filter(t){return arguments.length?(null===t?this.resetFilters():t instanceof Array&&t[0]instanceof Array&&!t.isFiltered?t[0].forEach(t=>this.toggleFilter(t)):this.toggleFilter(t),this.applyFilters(),this.notifyListeners(t),this):0<this.filters.length?this.filters[0]:null}toggleFilter(t){this.hasFilter(t)?this.removeFilter(t):this.addFilter(t)}addFilter(t){this.filters.push(t)}removeFilter(e){this.filters=this.filters.filter(t=>!(e<=t&&t<=e))}resetFilters(){this.filters=[]}dispose(){}}export{FilterHandler};